spec.rawSQL:
SELECT 
    array_join(
        concat(
            transform(split('${signal:csv}', ','), x -> 'AVG(' || REPLACE(x, ' ', '') || ') AS AVG_' || x),
            transform(split('${signal:csv}', ','), x -> 'MIN(' || REPLACE(x, ' ', '') || ') AS MIN_' || x),
            transform(split('${signal:csv}', ','), x -> 'MAX(' || REPLACE(x, ' ', '') || ') AS MAX_' || x)
        ),
        ', '
    );
